import{_ as t,o as e,c as d,O as a}from"./chunks/framework.bdcb0ee1.js";const g=JSON.parse('{"title":"Formatting & BBCode","description":"","frontmatter":{},"headers":[],"relativePath":"userguide/formatting.md","filePath":"userguide/formatting.md","lastUpdated":1773166218000}'),o={name:"userguide/formatting.md"},r=a('<h1 id="formatting-bbcode" tabindex="-1">Formatting &amp; BBCode <a class="header-anchor" href="#formatting-bbcode" aria-label="Permalink to &quot;Formatting &amp; BBCode&quot;">​</a></h1><p>Posts, signatures and other content areas on the board use BBCode for formatting. BBCode tags are written using square brackets and are converted to formatted text when displayed.</p><nav class="table-of-contents"><ul><li><a href="#text-formatting">Text formatting</a></li><li><a href="#structure">Structure</a></li><li><a href="#links-and-media">Links and media</a></li><li><a href="#mentions">Mentions</a></li><li><a href="#emoticons-and-emoji">Emoticons and emoji</a></li><li><a href="#markdown">Markdown</a></li></ul></nav><h2 id="text-formatting" tabindex="-1">Text formatting <a class="header-anchor" href="#text-formatting" aria-label="Permalink to &quot;Text formatting&quot;">​</a></h2><table><thead><tr><th>Tag</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td><code>[B]text[/B]</code></td><td><strong>Bold</strong></td><td><strong>text</strong></td></tr><tr><td><code>[I]text[/I]</code></td><td><em>Italic</em></td><td><em>text</em></td></tr><tr><td><code>[U]text[/U]</code></td><td>Underline</td><td></td></tr><tr><td><code>[S]text[/S]</code></td><td><s>Strikethrough</s></td><td></td></tr><tr><td><code>[SIZE=4]text[/SIZE]</code></td><td>Font size</td><td></td></tr><tr><td><code>[COLOR=#ff0000]text[/COLOR]</code></td><td>Text colour</td><td></td></tr><tr><td><code>[FONT=Arial]text[/FONT]</code></td><td>Font family</td><td></td></tr></tbody></table><h2 id="structure" tabindex="-1">Structure <a class="header-anchor" href="#structure" aria-label="Permalink to &quot;Structure&quot;">​</a></h2><table><thead><tr><th>Tag</th><th>Description</th></tr></thead><tbody><tr><td><code>[QUOTE=Author]text[/QUOTE]</code></td><td>Quote block with optional author name</td></tr><tr><td><code>[CODE]text[/CODE]</code></td><td>Code block with monospaced font</td></tr><tr><td><code>[SPOILER]text[/SPOILER]</code></td><td>Hidden content revealed on click</td></tr><tr><td><code>[LIST][*]item[/LIST]</code></td><td>Unordered (bullet) list</td></tr><tr><td><code>[OL][*]item[/OL]</code></td><td>Ordered (numbered) list</td></tr><tr><td><code>[CENTER]text[/CENTER]</code></td><td>Centre-aligned text</td></tr><tr><td><code>[LEFT]text[/LEFT]</code></td><td>Left-aligned text</td></tr><tr><td><code>[RIGHT]text[/RIGHT]</code></td><td>Right-aligned text</td></tr></tbody></table><h2 id="links-and-media" tabindex="-1">Links and media <a class="header-anchor" href="#links-and-media" aria-label="Permalink to &quot;Links and media&quot;">​</a></h2><table><thead><tr><th>Tag</th><th>Description</th></tr></thead><tbody><tr><td><code>[URL=https://example.com]text[/URL]</code></td><td>Hyperlink (opens in a new tab)</td></tr><tr><td><code>[EMAIL]user@example.com[/EMAIL]</code></td><td>Email link</td></tr><tr><td><code>[IMG]https://example.com/image.png[/IMG]</code></td><td>Embedded image</td></tr><tr><td><code>[YOUTUBE]video_id[/YOUTUBE]</code></td><td>YouTube video embed</td></tr></tbody></table><h2 id="mentions" tabindex="-1">Mentions <a class="header-anchor" href="#mentions" aria-label="Permalink to &quot;Mentions&quot;">​</a></h2><p>Type <code>@username</code> anywhere in your post to mention another member. They will receive a notification. Mentions are detected automatically — no special BBCode tag is needed.</p><h2 id="emoticons-and-emoji" tabindex="-1">Emoticons and emoji <a class="header-anchor" href="#emoticons-and-emoji" aria-label="Permalink to &quot;Emoticons and emoji&quot;">​</a></h2><p>Your board may have custom emoticons configured by the administrator. Type the emoticon code (e.g. <code>:smile:</code>) and it will be converted to an image. Native emoji characters are also supported and will be rendered as-is.</p><h2 id="markdown" tabindex="-1">Markdown <a class="header-anchor" href="#markdown" aria-label="Permalink to &quot;Markdown&quot;">​</a></h2><p>Basic Markdown syntax is also supported alongside BBCode. You can use headings, bold, italic, links and lists using standard Markdown notation.</p>',15),n=[r];function i(c,s,l,m,h,u){return e(),d("div",null,n)}const p=t(o,[["render",i]]);export{g as __pageData,p as default};
